#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
fix-cycling-files.py - Regenere tous les fichiers manquants du module cycling
favourites et patche pariscore.js + server.js chirurgicalement.

Usage:
    cd <repo-pariscore>
    python fix-cycling-files.py

Prerequis: Python 3.x (aucune dependance externe)
"""
import base64
import json
import os
import sys

# Les donnees (fichiers + patches) sont encodees en base64 pour eviter
# tout probleme d'echappement. Elles sont injectees par le script generateur.
_DATA_B64 = ""

DATA = json.loads(base64.b64decode(_DATA_B64).decode("utf-8"))
FILES_BASE64 = DATA["files"]
PATCHES = DATA["patches"]


def main():
    if not os.path.exists("pariscore.html"):
        print("ERREUR: pariscore.html non trouve dans le dossier courant.")
        print("   Lance ce script depuis la racine du repo pariscore.")
        sys.exit(1)

    print("=== Creation des fichiers manquants ===")
    for path, b64 in FILES_BASE64.items():
        dirpath = os.path.dirname(path)
        if dirpath:
            os.makedirs(dirpath, exist_ok=True)
        content = base64.b64decode(b64)
        with open(path, "wb") as f:
            f.write(content)
        print("  OK Cree " + path + " (" + str(len(content)) + " bytes)")

    print()
    print("=== Patch de pariscore.js ===")
    with open("pariscore.js", "r", encoding="utf-8") as f:
        content = f.read()

    for i, patch in enumerate(PATCHES["pariscore_js"]):
        old = patch["old"]
        new = patch["new"]
        if old in content:
            content = content.replace(old, new, 1)
            print("  OK Patch " + str(i + 1) + " applique")
        elif new in content:
            print("  WARN Patch " + str(i + 1) + " deja applique (ignore)")
        else:
            print("  FAIL Patch " + str(i + 1) + ": anchor non trouve!")
            print("    Looking for (first 200 chars): " + old[:200] + "...")
            sys.exit(1)

    with open("pariscore.js", "w", encoding="utf-8") as f:
        f.write(content)
    print("  OK pariscore.js sauvegarde")

    print()
    print("=== Patch de server.js ===")
    with open("server.js", "r", encoding="utf-8") as f:
        content = f.read()

    for i, patch in enumerate(PATCHES["server_js"]):
        old = patch["old"]
        new = patch["new"]
        if old in content:
            content = content.replace(old, new, 1)
            print("  OK Patch " + str(i + 1) + " applique")
        elif new in content:
            print("  WARN Patch " + str(i + 1) + " deja applique (ignore)")
        else:
            print("  FAIL Patch " + str(i + 1) + ": anchor non trouve!")
            sys.exit(1)

    with open("server.js", "w", encoding="utf-8") as f:
        f.write(content)
    print("  OK server.js sauvegarde")

    print()
    print("=== Nettoyage des fichiers de doc a la racine ===")
    for fname in ["README-INSTALL.md", "pariscore-cycling-favourites.patch", "stage-favourites.json"]:
        if os.path.exists(fname):
            os.remove(fname)
            print("  OK Supprime " + fname)
        else:
            print("  INFO " + fname + " inexistant")

    print()
    print("=== TERMINE ===")
    print()
    print("Tous les fichiers ont ete crees/patches. Prochaines etapes:")
    print('  1. git add -A')
    print('  2. git commit -m "fix(cycling): add missing source files + scripts + patch pariscore.js/server.js"')
    print('  3. git push')
    print()
    print("Puis sur le VPS:")
    print("  bash deploy.sh")
    print("  pm2 restart pariscore")
    print("  bash ~/pariscore/scripts/setup-cycling-cron.sh")


if __name__ == "__main__":
    main()
